var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 줄 서세요. 줄. 할아버지께서 새치기는 나쁜 거라고 하셨어요.","JPN":"さあ、1列にお並びください。お祖父様は割り込みはいけないことだと言っていました。","ENG":"Now, please stand in line. Grandfather said that cutting in line is rude.","TWN":"來，請排好隊，我爺爺說插隊是不好的行為。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"나쁜 아이에게는 얼터니움 리액터를 제일 마지막에 드릴 거예요.","JPN":"悪い子はオルタニウムリアクターをあげるのを一番最後にしますよ。","ENG":"Bad children will be the last to receive their Alternium Reactors.","TWN":"不聽話的小朋友最後才能拿到黑化永恆之金電抗器喔。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 저걸 장비에 연결하면 엄청 강해진다는 거지?","JPN":"つまり……あれを装備につければすごく強くなるってことよね？","ENG":"So... If I connect this to my gear, it will become incredibly powerful?","TWN":"那個……把這個連接到裝備上就會變超強對吧？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 것 같네요. 사장님은 또 어디서 저런 재미있는 걸 만들어 오신 걸까요?","JPN":"そうみたいですね。社長はどこであんなおもしろいものを作って来たんでしょうか？","ENG":"That seems to be the case. Which hat do you think Boss pulled this idea out from?","TWN":"好像是這樣，老闆不知道又從哪弄來這麼有趣的東西？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님? 알파트릭스 회장님이 만든 거 아니었어?","JPN":"社長？　アルファトリックス会長が作ったんじゃないの？","ENG":"Boss? It wasn’t the Alphatrix's President who made this?","TWN":"老闆？這不是阿爾法崔克斯的會長製造的嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아. 물론 대외적으로는 그렇긴 합니다만, 그 재료를 저희 사장님이 공급했다는 이야기가 있더라고요.","JPN":"あ、もちろん対外的にはそうなんですが、あれの材料をうちの社長が提供したという話があってですね。","ENG":"Well, publicly, yes. However, there are rumors that our Boss provided the materials.","TWN":"喔～那是對外的說法啦，我聽說材料是老闆提供的。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 대단하네…… 알파트릭스 같은 대기업에 납품도 다 하고.","JPN":"すごいね……アルファトリックスのような大企業に納品までするなんて。","ENG":"That’s impressive... Supplying to a conglomerate like Alphatrix...","TWN":"這麼厲害喔……還提供阿爾法崔克斯這種大企業材料。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 하나 받으셨어요?","JPN":"ミナさんは受け取りましたか？","ENG":"Did you receive one too, Mina?","TWN":"米娜你有拿到嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 나?","JPN":"えっ？　私？","ENG":"Huh? Me?","TWN":"嗯？我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 아니. 내 장비랑은 호환이 안 된다고 하더라고.","JPN":"あはは、それがさ。私の装備とは合わないんだって。","ENG":"Ah hah hah, no. Apparently it’s not compatible with my gear.","TWN":"哈哈，我沒有欸，她說和我的裝備不相容。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"재고도 얼마 없어서 일단은 알트 소대원부터 지급하기로 했대.","JPN":"在庫も少ないから、とりあえずアルト小隊員から支給することにしたんだって。","ENG":"Also, she doesn’t have a lot of stock, so they’ve decided to equip ALT Squad first.","TWN":"而且庫存也不多，所以就先給阿爾特小隊的人。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하하! 어떠냐, 이게 바로 얼터니움 리액터란 말씀이야!","JPN":"はは！　どうだ、これがオルタニウムリアクターだ！","ENG":"Ha ha! Take that! This is the Alternium Reactor!","TWN":"哈哈！怎麼樣？這就是黑化永恆之金電抗器！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이게 있으니까 3종…… 아니지! 4종 침식체도 혼자 상대할 수 있을 것 같다구!","JPN":"これがあれば第3種……いや！　第4種侵食体を相手にしても一人で戦えるぞ！","ENG":"With this, I feel like I can take on a Category 3... No, a Category 4 Corrupted Object by myself!","TWN":"只要有這個，管他是3類……不！就算是4類侵蝕體，我好像都能自己應付欸！"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잘은 모르겠지만 보고 있으면 뭔가 찌릿찌릿한 느낌이 드네.","JPN":"よくわからないけれど、見ていると何だかチリチリする感じがするね。","ENG":"I’m not sure about that, but I do get a tingling feeling when I look at it.","TWN":"總覺得好像光是用看的，都有點刺痛的感覺。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"출력이 엄청나서 그런 걸까?","JPN":"出力がすごすぎてそうなのかな？","ENG":"Maybe it’s because of its massive output?","TWN":"是因為輸出太強的關係嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"당연하지! 그럼 강해진 기념으로 화력 테스트나 해 볼까?","JPN":"そうに決まってる！　じゃあ、強くなった記念に火力テストでもしてみようか？","ENG":"Of course that’s why! To commemorate the upgrade, let’s test the puppy out!","TWN":"當然！那就當作是慶祝變強，來測試一下火力吧？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말? 그거 기대되는데.","JPN":"本当？　おもしろそうね。","ENG":"Really? I can’t wait!","TWN":"真的嗎？好期待喔。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};